import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { UploadCloud, FileText, CheckCircle, AlertCircle } from 'lucide-react';

const API_BASE_URL = "http://127.0.0.1:5000/api";

const Uploads = () => {
  const userId = localStorage.getItem('userId');
  const [file, setFile] = useState(null);
  const [datasets, setDatasets] = useState([]);
  const [statusMsg, setStatusMsg] = useState("");

  useEffect(() => {
    fetchDatasets();
  }, []);

  const fetchDatasets = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/user-datasets`, { headers: { 'X-User-ID': userId } });
      setDatasets(res.data);
    } catch (error) { console.error("Error fetching files", error); }
  };

  const handleUpload = async () => {
    if(!file) return setStatusMsg("Please select a file.");
    
    setStatusMsg("Uploading...");
    const formData = new FormData();
    formData.append('file', file);
    
    try {
      await axios.post(`${API_BASE_URL}/upload-data`, formData, { headers: { 'X-User-ID': userId } });
      setStatusMsg("Success!");
      fetchDatasets(); // Refresh list
      setTimeout(() => setStatusMsg(""), 2000);
    } catch (e) { setStatusMsg("Upload Failed"); }
  };

  return (
    <div style={{ padding: '30px', maxWidth: '1000px', margin: '0 auto' }}>
      <h2 style={{ color: '#2e7d32', marginBottom: '20px' }}>📂 Data Management</h2>

      {/* UPLOAD CARD */}
      <div style={{ background: 'white', padding: '30px', borderRadius: '12px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', marginBottom: '30px', textAlign: 'center' }}>
        <div style={{ border: '2px dashed #ccc', borderRadius: '8px', padding: '40px', cursor: 'pointer' }}>
          <UploadCloud size={48} color="#2e7d32" style={{ marginBottom: '15px' }} />
          <p style={{ fontSize: '1.1rem', color: '#555' }}>Drag and drop your Excel/CSV file here</p>
          <input type="file" onChange={e => setFile(e.target.files[0])} style={{ marginTop: '15px' }} />
        </div>
        <button onClick={handleUpload} style={{ marginTop: '20px', padding: '12px 30px', background: '#2e7d32', color: 'white', border: 'none', borderRadius: '6px', fontSize: '16px', cursor: 'pointer' }}>
            Upload Activity Data
        </button>
        {statusMsg && <p style={{ marginTop: '10px', color: statusMsg.includes('Success') ? 'green' : 'red', fontWeight: 'bold' }}>{statusMsg}</p>}
      </div>

      {/* FILE LIST */}
      <h3 style={{ color: '#444', marginBottom: '15px' }}>📜 Audit History</h3>
      <div style={{ background: 'white', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' }}>
        {datasets.length === 0 ? <p style={{ padding: '20px', color: '#888' }}>No files uploaded yet.</p> : datasets.map(ds => (
          <div key={ds.dataset_id} style={{ padding: '20px', borderBottom: '1px solid #eee', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
              <div style={{ padding: '10px', background: '#e8f5e9', borderRadius: '8px' }}><FileText color="#2e7d32" /></div>
              <div>
                <div style={{ fontWeight: 'bold', color: '#333' }}>{ds.filename}</div>
                <div style={{ fontSize: '0.85rem', color: '#888' }}>Uploaded: {ds.upload_date}</div>
              </div>
            </div>
            {/* Simple Status Badge */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '5px', color: 'green', fontSize: '0.9rem', fontWeight: 'bold' }}>
              <CheckCircle size={16} /> Data Ready
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Uploads;
